objects.draw:
function(ctx, obj) {
  ctx.save();

  // Desenhar roldana
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w, 0, 2 * Math.PI);
  ctx.fillStyle = obj.fill;
  ctx.fill();
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth;
  ctx.stroke();

  // Canal da corda
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w - 3, 0, 2 * Math.PI);
  ctx.fillStyle = '#1e293b';
  ctx.fill();

  // Eixo
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w * 0.2, 0, 2 * Math.PI);
  ctx.fillStyle = '#0f172a';
  ctx.fill();

  // Raios para indicar rotação
  if (obj.rotationAngle) {
    ctx.save();
    ctx.translate(obj.x, obj.y);
    ctx.rotate(obj.rotationAngle);
    for (let i = 0; i < 4; i++) {
      const angle = (i * Math.PI * 2) / 4;
      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.lineTo(Math.cos(angle) * obj.w * 0.7, Math.sin(angle) * obj.w * 0.7);
      ctx.strokeStyle = '#fbbf24';
      ctx.lineWidth = 2;
      ctx.stroke();
    }
    ctx.restore();
  }

  // Desenhar corda
  if (obj.ropeLeftY !== undefined && obj.ropeRightY !== undefined) {
    // Corda esquerda
    ctx.beginPath();
    ctx.moveTo(obj.x - obj.w * 0.8, obj.y + obj.w * 0.3);
    ctx.lineTo(obj.x - obj.w * 0.5, obj.y + obj.w * 0.5);
    ctx.lineTo(obj.x - 5, obj.ropeLeftY);
    ctx.strokeStyle = obj.ropeColor;
    ctx.lineWidth = obj.ropeWidth;
    ctx.stroke();

    // Corda direita
    ctx.beginPath();
    ctx.moveTo(obj.x + obj.w * 0.8, obj.y + obj.w * 0.3);
    ctx.lineTo(obj.x + obj.w * 0.5, obj.y + obj.w * 0.5);
    ctx.lineTo(obj.x + 5, obj.ropeRightY);
    ctx.stroke();
  }

  ctx.restore();
}

objects.update:
function(obj, dt) {
  if (!obj.leftMassObj || !obj.rightMassObj) return;

  const m1 = obj.leftMass;
  const m2 = obj.rightMass;
  const I = obj.momentOfInertia;
  const r = obj.w / 100;
  const g = Lab.state.gravity;
  const friction = obj.friction;
  const ropeFriction = obj.ropeFriction;

  // Calcular aceleração considerando inércia da roldana e atrito
  const denominator = m1 + m2 + I / (r * r);
  let a = (m2 - m1) * g / denominator;

  // Atrito da corda (força oposta ao movimento)
  if (obj.angularVelocity) {
    const frictionForce = friction * (m1 + m2) * g;
    const frictionAcc = frictionForce / denominator;
    if (a > 0) a = Math.max(0, a - frictionAcc);
    else if (a < 0) a = Math.min(0, a + frictionAcc);
  }

  // Atrito da roldana
  const angularFriction = obj.angularVelocity * ropeFriction;

  // Atualizar velocidades
  obj.velocity = (obj.velocity || 0) + a * dt;
  obj.velocity *= (1 - friction * dt);

  // Velocidade angular da roldana
  obj.angularVelocity = (obj.velocity / r) * dt + (obj.angularVelocity || 0);
  obj.angularVelocity *= (1 - angularFriction * dt);
  obj.rotationAngle = (obj.rotationAngle || 0) + obj.angularVelocity * dt * 30;

  // Atualizar posições das massas
  obj.leftPosition = (obj.leftPosition || 300) - obj.velocity * dt;
  obj.rightPosition = (obj.rightPosition || 300) + obj.velocity * dt;

  // Limites
  obj.leftPosition = Math.max(50, Math.min(obj.y + 100, obj.leftPosition));
  obj.rightPosition = Math.max(50, Math.min(obj.y + 100, obj.rightPosition));

  // Atualizar objetos das massas
  if (obj.leftMassObj) {
    obj.leftMassObj.y = obj.leftPosition;
    obj.leftMassObj.x = obj.x - 80;
  }
  if (obj.rightMassObj) {
    obj.rightMassObj.y = obj.rightPosition;
    obj.rightMassObj.x = obj.x + 80;
  }

  obj.ropeLeftY = obj.leftPosition + 15;
  obj.ropeRightY = obj.rightPosition + 15;
}

objects.draw:
function(ctx, obj) {
  ctx.save();
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w, 0, 2 * Math.PI);
  ctx.fillStyle = obj.fill;
  ctx.fill();
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth;
