tools.action:
function() {
  const centerX = Lab.state.W / 2;
  const pulleyY = 150;
  const massY = 350;

  // Criar roldana
  const pulley = Lab.objects.add({
    type: 'rect',
    pluginId: 'atwood_pulley',
    x: centerX - 20,
    y: pulleyY - 20,
    w: 40,
    h: 40,
    mass: 2,
    momentOfInertia: 0.5,
    friction: 0.05,
    ropeFriction: 0.02,
    fill: '#94a3b8',
    stroke: '#475569',
    lineWidth: 2,
    static: true,
    leftMass: 1,
    rightMass: 1,
    leftPosition: massY,
    rightPosition: massY,
    ropeLength: 400,
    ropeColor: '#64748b',
    ropeWidth: 3,
    velocity: 0,
    angularVelocity: 0,
    rotationAngle: 0
  });

  // Criar massa esquerda
  const leftMass = Lab.objects.add({
    type: 'circle',
    pluginId: 'atwood_mass',
    x: centerX - 80,
    y: massY,
    w: 30,
    mass: 1,
    fill: '#3b82f6',
    stroke: '#1d4ed8',
    lineWidth: 2,
    collidable: true
  });

  // Criar massa direita
  const rightMass = Lab.objects.add({
    type: 'circle',
    pluginId: 'atwood_mass',
    x: centerX + 80,
    y: massY,
    w: 30,
    mass: 1,
    fill: '#ef4444',
    stroke: '#dc2626',
    lineWidth: 2,
    collidable: true
  });

  // Conectar objetos à roldana
  const pulleyObj = Lab.objects.get(pulley);
  pulleyObj.leftMassObj = Lab.objects.get(leftMass);
  pulleyObj.rightMassObj = Lab.objects.get(rightMass);
  pulleyObj.leftMass = 1;
  pulleyObj.rightMass = 1;
  pulleyObj.leftPosition = massY;
  pulleyObj.rightPosition = massY;
  pulleyObj.ropeLeftY = massY + 15;
  pulleyObj.ropeRightY = massY + 15;

  alert('Máquina de Atwood criada!\n\nMassas: 1kg cada\nRaio da roldana: 40px\nAtrito da corda: 0.05\nAtrito da roldana: 0.02\n\nInicie a simulação para ver o movimento!');
}

