function() {
  const atwoodPulley = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (atwoodPulley) {
    const m1 = parseFloat(prompt('Massa esquerda (kg):', atwoodPulley.leftMass || 1));
    const m2 = parseFloat(prompt('Massa direita (kg):', atwoodPulley.rightMass || 1));

    if (!isNaN(m1) && !isNaN(m2) && m1 > 0 && m2 > 0) {
      atwoodPulley.leftMass = m1;
      atwoodPulley.rightMass = m2;
      if (atwoodPulley.leftMassObj) atwoodPulley.leftMassObj.mass = m1;
      if (atwoodPulley.rightMassObj) atwoodPulley.rightMassObj.mass = m2;

      const diff = Math.abs(m1 - m2);
      const acceleration = (diff * 9.8) / (m1 + m2 + (atwoodPulley.momentOfInertia / Math.pow(atwoodPulley.w/100, 2)));

      alert(`Massas ajustadas!\n\nEsquerda: ${m1} kg\nDireita: ${m2} kg\nDiferença: ${diff} kg\nAceleração teórica: ${acceleration.toFixed(2)} m/s²\n\nInicie a simulação para ver o movimento.`);
    }
  } else {
    alert('Nenhuma máquina de Atwood encontrada. Crie uma primeiro.');
  }
}

